public static double findWeight(Product[] catalog, String id) {
    int i = 0;
    while (i < catalog.length && catalog[i] != null) {
        if (catalog[i].getSku().equals(id)) {
            return catalog[i].getUnitWeight();
        }
        i++;
    }
    return 0.0;
}
```

