public double calculateTotalMass(Product[] catalog) {
    double total = 0.0;

    for (int i = 0; i < spCount; i++) {
        String id = spList[i].getSku();
        double w = findWeight(catalog, id);
        total += (spList[i].getQuantity() * w) + smallFee;
    }

    for (int j = 0; j < lpCount; j++) {
        String id = lpList[j].getSku();
        double w = findWeight(catalog, id);
        total += (lpList[j].getQuantity() * w) + largeFee;
    }

    return total;
}
```

